<script>
 import{onMount}from'svelte';import{BarChart3,Sparkles,Check,XCircle,RefreshCw,TriangleAlert,ClipboardCheck}from'lucide-svelte';let data=$state(null),plans=$state([]),loading=$state(true),message=$state(''),error=$state('');onMount(load);
 async function load(){loading=true;const[e,u]=await Promise.all([fetch('/api/evaluation'),fetch('/api/upgrades')]);const d=await e.json();const p=await u.json();if(e.ok)data=d;else error=d.error;plans=p.plans??[];loading=false}
 async function generate(){const r=await fetch('/api/evaluation',{method:'POST',headers:{'content-type':'application/json'},body:'{"operation":"generate"}'});const d=await r.json();if(!r.ok)error=d.error;else message=`Generated ${d.proposals.length} new proposal(s)`;await load()}
 async function decide(id,status){const r=await fetch('/api/evaluation',{method:'POST',headers:{'content-type':'application/json'},body:JSON.stringify({operation:'decide',id,status})});const d=await r.json();if(!r.ok)error=d.error;else message=`Proposal ${status}`;await load()}
 async function prepare(proposalId){loading=true;message='Running fixed baseline gates…';const r=await fetch('/api/upgrades',{method:'POST',headers:{'content-type':'application/json'},body:JSON.stringify({operation:'prepare',proposalId})});const d=await r.json();if(!r.ok)error=d.error;else message=`Upgrade plan ${d.plan.status}`;await load()}
 async function verify(id){loading=true;const r=await fetch('/api/upgrades',{method:'POST',headers:{'content-type':'application/json'},body:JSON.stringify({operation:'verify',id})});const d=await r.json();if(!r.ok)error=d.error;else message=`Plan ${d.plan.status}`;await load()}
</script>
<svelte:head><title>Evaluation · J.A.R.V.I.S.</title></svelte:head><div class="page"><header><BarChart3 size={22}/><div><h1>Capability Evaluation</h1><p>Measured reliability and evidence-backed improvement governance.</p></div><button onclick={load} disabled={loading}><RefreshCw size={14}/>Refresh</button><button class="primary" onclick={generate}><Sparkles size={14}/>Generate proposals</button></header>{#if error}<p class="error">{error}</p>{/if}{#if message}<p class="success">{message}</p>{/if}{#if data}<section class="stats"><article><strong>{data.summary.totalExecutions}</strong><span>executions</span></article><article><strong>{data.summary.successRate}%</strong><span>success rate</span></article><article><strong>{data.summary.modelFailures}/{data.summary.modelRuns}</strong><span>model failures</span></article><article><strong>{data.summary.proposalsOpen}</strong><span>open proposals</span></article></section><section class="columns"><article class="panel"><h2>Capability performance</h2>{#each data.capabilities as item(item.capability)}<div class="metric"><div><strong>{item.capability}</strong><span>{item.kind} · {item.runs} runs · {item.averageDurationMs}ms avg</span></div><b class:bad={item.successRate<80}>{item.successRate}%</b></div>{/each}{#if !data.capabilities.length}<p class="empty">Run tools or models to collect metrics.</p>{/if}</article><article class="panel"><h2>Recent failures</h2>{#each data.recentFailures as item(item.id)}<div class="failure"><TriangleAlert size={14}/><div><strong>{item.capability}</strong><span>{item.error}</span></div></div>{/each}{#if !data.recentFailures.length}<p class="empty">No recorded failures.</p>{/if}</article></section><section class="panel"><h2>Improvement proposals</h2>{#each data.proposals as proposal(proposal.id)}<article class="proposal"><div><div class="title"><strong>{proposal.title}</strong><b>{proposal.risk} risk</b><em>{proposal.status}</em></div><p>{proposal.rationale}</p><small>Target: {proposal.target}</small>{#each proposal.evidence as evidence(evidence)}<code>{evidence}</code>{/each}</div>{#if proposal.status==='proposed'}<button onclick={()=>decide(proposal.id,'approved')}><Check size={14}/>Approve direction</button><button onclick={()=>decide(proposal.id,'dismissed')}><XCircle size={14}/>Dismiss</button>{:else if proposal.status==='approved'&&!plans.some(plan=>plan.proposalId===proposal.id)}<button onclick={()=>prepare(proposal.id)}><ClipboardCheck size={14}/>Prepare upgrade</button>{/if}</article>{/each}{#if !data.proposals.length}<p class="empty">No proposals. Generate them after sufficient execution evidence exists.</p>{/if}</section><section class="panel"><h2>Evaluated upgrade plans</h2>{#each plans as plan(plan.id)}<article class="proposal"><div><div class="title"><strong>{plan.title}</strong><em>{plan.status}</em></div><p>{plan.steps.join(' → ')}</p>{#each plan.validation as gate(gate.command)}<code>{gate.ok?'PASS':'FAIL'} · {gate.command} · {gate.durationMs}ms</code>{/each}</div>{#if plan.status==='ready'}<button onclick={()=>verify(plan.id)}><Check size={14}/>Verify again</button>{/if}</article>{/each}{#if !plans.length}<p class="empty">Approved proposals can be prepared into baseline-validated plans.</p>{/if}</section>{/if}</div>
